/* 代码头注释：说明算法名称和关键技巧 */
// 算法名称：计数图的最小生成树
// 关键技巧：Kruskal 算法的逆向思维，组合数学，并查集优化

#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int INF = 0x3f3f3f3f;
const int MOD = 998244353;

struct Edge {
    int u, v, w;
    bool operator<(const Edge& other) const {
        return w < other.w;
    }
};

vector<int> parent, rank_;

int find(int x) {
    if (parent[x] != x) {
        parent[x] = find(parent[x]);
    }
    return parent[x];
}

void unite(int x, int y) {
    x = find(x);
    y = find(y);
    if (x != y) {
        if (rank_[x] < rank_[y]) {
            swap(x, y);
        }
        parent[y] = x;
        if (rank_[x] == rank_[y]) {
            rank_[x]++;
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, K;
    cin >> n >> K;
    vector<Edge> edges(n - 1);
    for (int i = 0; i < n - 1; ++i) {
        cin >> edges[i].u >> edges[i].v >> edges[i].w;
    }

    // 按边权排序
    sort(edges.begin(), edges.end());

    // 初始化并查集
    parent.resize(n + 1);
    rank_.resize(n + 1, 0);
    for (int i = 1; i <= n; ++i) {
        parent[i] = i;
    }

    ll result = 1;
    for (const auto& edge : edges) {
        int u = edge.u, v = edge.v, w = edge.w;
        if (find(u) != find(v)) {
            unite(u, v);
            // 计算非树边的可能取值
            result = result * (K - w + 1) % MOD;
        }
    }

    cout << result << endl;

    return 0;
}

